import React from 'react';
import { Col, Container, Row } from 'react-bootstrap';
import Abdallah from '../assets/images/main.png';

function Header() {
    return (
        <Container className='header'>
            <Row>
                <Col className='main-image rounded mx-auto d-block' xs={'auto'} md={5}>
                    <img data-aos="zoom-out-left" src={Abdallah} alt="abdallah" /> 
                </Col>
                <Col className="paragraph" data-aos="fade-right" md={7}>
                    <h3>Welcome to Abdallah's Protofolio</h3>
                    <p>Abdallah is A Junior PHP Laravel Developer With One-Year Experience, Also He is React Begginerand He Can Works With Different Technologies Like Bootstrap With All It's Versions  </p>
                </Col>
            </Row>
        </Container>
    )
}

export default Header
