import React from 'react'
import { Link ,BrowserRouter as Router} from 'react-router-dom'
import Whatsapp from '../assets/images/icons/whatsapp.svg';
import Facebook from '../assets/images/icons/facebook.svg';
import Linked from '../assets/images/icons/linkedin.png';
import { Col, Container, Row } from 'react-bootstrap';

function Footer() {
    return (
        <Router>
            <Container className="footer" fluid>
                <Row>
                    <Col className="item" xs={'auto'}  >
                        <div className="linked">
                            <Link target="_blank" to={{ pathname: "https://www.linkedin.com/in/abdallah-hamada-89a06b194" }}>
                                <img src={Linked} alt="linked in" />
                                <span>/abdallah-hamada-89a06b194</span>
                            </Link>
                        </div>
                    </Col>
                    <Col className="item" xs={'auto'} >
                        <div className="facebook">
                            <Link className="facebook" target="_blank" to={{ pathname: "https://www.facebook.com/abdo.hamda2017" }}>
                                <img src={Facebook} alt="facebook" />
                                <span>/abdo.hamda2017</span>
                            </Link> 
                        </div>
                    </Col>
                    <Col className="item" xs={'auto'} >
                        <div className="whatsapp">
                            <img src={Whatsapp} alt="whatsapp" />
                            <span>+201093594038</span>
                        </div>
                    </Col>
                    <Col className="right" xs={'auto'} md={{offset:6}} >
                        <span>All Rights reserved<span className="name"> Abdallah Hamada</span><sup>&copy;</sup> {new Date().getFullYear()}</span>
                    </Col>
                </Row>
            </Container>
        </Router>
    )
}

export default Footer
