import React from 'react'
import PHP from '../assets/images/icons/php.svg';
import  Laravel from '../assets/images/icons/laravel.svg';
import Mysql from '../assets/images/icons/mysql.svg';
import Html from '../assets/images/icons/html5.svg';
import Css from '../assets/images/icons/css3.svg';
import JS from '../assets/images/icons/js.png';
import ES6 from '../assets/images/icons/es6.jpg';
import Jquery from '../assets/images/icons/jquery.svg';
import Bootstrap from '../assets/images/icons/bootstrap.png';
import Sass from '../assets/images/icons/sass.svg';
import Ajax from '../assets/images/icons/ajax.svg';
import Json from '../assets/images/icons/json.svg';
import Reactjs from '../assets/images/icons/react.svg';
import Git from '../assets/images/icons/git.png';
import GitHub from '../assets/images/icons/github.png';
import { Col, Container, Row } from 'react-bootstrap';

function Skills() {
    return (
            <Container fluid className='skills' data-aos="zoom-out-left">
                <Row>
                    <Col>
                        <img src={PHP} alt="php" />
                        <span>PHP</span>
                    </Col>
                    <Col>
                        <img src={Laravel} alt="laravel" />
                        <span>LARAVEL</span>
                    </Col>
                    <Col>
                        <img src={Mysql} alt="mysql" />
                        <span>MYSQL</span>
                    </Col>
                    <Col>
                        <img src={Html} alt="html" />
                        <span>HTML</span>
                    </Col>
                    <Col>
                        <img src={Css} alt="css" />
                        <span>CSS</span>
                    </Col>
                    <Col>
                        <img src={JS} alt="js" />
                        <span>JS, DOM, BOM</span>
                    </Col>
                    <Col>
                        <img src={ES6} alt="es6" />
                        <span>ES6</span>
                    </Col>
                    <Col>
                        <img src={Jquery} alt="jquery" />
                        <span>JQUERY</span>
                    </Col>
                    <Col>
                        <img src={Bootstrap} alt="bootstrap" />
                        <span>BOOTSTRAP</span>
                    </Col>
                    <Col>
                        <img src={Sass} alt="sass" />
                        <span>SASS</span>
                    </Col>
                    <Col>
                        <img src={Ajax} alt="ajax" />
                        <span>AJAX</span>
                    </Col>
                    <Col>
                        <img src={Json} alt="json" />
                        <span>JSON</span>
                    </Col>
                    <Col>
                        <img src={Reactjs} alt="react" />
                        <span>REACT JS</span>
                    </Col>
                    <Col>
                        <img src={Git} alt="git" />
                        <span>GIT</span>
                    </Col>
                    <Col>
                        <img src={GitHub} alt="github" /> 
                        <span>GitHub</span>
                    </Col>
                </Row>
            </Container>        
    )
}

export default Skills
